export interface ExportGitSemanticStoreOptions {
    /** Explicit SQLite path. The source is opened only through withReadonlyDb. */
    dbPath: string;
    repoId: number;
    worktreeRoot: string;
}
export interface ImportGitSemanticStoreOptions {
    worktreeRoot: string;
    /** Must not exist. Import never migrates, truncates, or overwrites a DB. */
    targetDbPath: string;
    /** Machine-local identity is supplied at import and never committed to Git. */
    targetRepoRootPath: string;
}
export interface GitSemanticStoreResult {
    storePath: string;
    semanticDigest: string;
    featureCount: number;
    specCount: number;
}
export declare function exportGitSemanticStore(options: ExportGitSemanticStoreOptions): GitSemanticStoreResult;
export declare function importGitSemanticStore(options: ImportGitSemanticStoreOptions): GitSemanticStoreResult & {
    repoId: number;
    dbPath: string;
};
